mapper.select:
SELECT *
FROM R_LOGIN_HISTORY_T
WHERE USER_ID = #{USER_ID}
ORDER BY LOGIN_AT DESC
LIMIT #{limit}

SELECT h.*, u.NAME AS USER_NAME, (SELECT MAX(a.CREATED_AT) FROM R_ACTIVITY_LOG_T a WHERE a.HISTORY_ID = h.HISTORY_ID) AS LAST_ACTIVITY_AT, (SELECT COUNT(*) FROM R_ACTIVITY_LOG_T a WHERE a.HISTORY_ID = h.HISTORY_ID AND a.ACTION_TYPE = 'CREATE') AS ACTIVITY_CREATE, (SELECT COUNT(*) FROM R_ACTIVITY_LOG_T a WHERE a.HISTORY_ID = h.HISTORY_ID AND a.ACTION_TYPE = 'UPDATE') AS ACTIVITY_UPDATE, (SELECT COUNT(*) FROM R_ACTIVITY_LOG_T a WHERE a.HISTORY_ID = h.HISTORY_ID AND a.ACTION_TYPE = 'DELETE') AS ACTIVITY_DELETE, (SELECT COUNT(*) FROM R_ACTIVITY_LOG_T a WHERE a.HISTORY_ID = h.HISTORY_ID AND a.ACTION_TYPE = 'VIEW') AS ACTIVITY_VIEW FROM R_LOGIN_HISTORY_T h LEFT JOIN R_USER_T u ON h.USER_ID = u.USER_ID
AND h.USER_ID = #{filterUserId}
AND h.LOGIN_TYPE = #{loginType}
AND h.LOGIN_AT >= #{startDate}
AND h.LOGIN_AT <= #{endDate}
AND (u.NAME LIKE CONCAT('%', #{search}, '%') OR h.IP_ADDRESS LIKE CONCAT('%', #{search}, '%') OR h.LOGIN_TYPE LIKE CONCAT('%', #{search}, '%'))
ORDER BY
u.NAME h.LOGIN_TYPE h.IP_ADDRESS h.LOGIN_AT h.LOGIN_AT
ASC DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM R_LOGIN_HISTORY_T h
LEFT JOIN R_USER_T u ON h.USER_ID = u.USER_ID


        AND h.USER_ID = #{filterUserId}


        AND h.LOGIN_TYPE = #{loginType}


        AND h.LOGIN_AT >= #{startDate}


        AND h.LOGIN_AT <= #{endDate}


        AND (u.NAME LIKE CONCAT('%', #{search}, '%')
             OR h.IP_ADDRESS LIKE CONCAT('%', #{search}, '%')
             OR h.LOGIN_TYPE LIKE CONCAT('%', #{search}, '%'))
